            if (nextRecord != null) {
                header = nextRecord.values();
            }
        } else {
            if (this.format.getSkipHeaderRecord()) {
                this.nextRecord();
            }
            header = formatHeader;
        }

        // build the name to index mappings
        if (header != null) {
            for (int i = 0; i < header.length; i++) {
                String headerName = header[i];
                if (hdrMap.containsKey(headerName)) {
                    // Handle duplicate header names by appending a counter
                    int counter = 1;
                    String uniqueName;
                    do {
                        uniqueName = headerName + "[" + counter + "]";
                        counter++;
                    } while (hdrMap.containsKey(uniqueName));
                    hdrMap.put(uniqueName, Integer.valueOf(i));
                } else {
                    hdrMap.put(headerName, Integer.valueOf(i));
                }
            }
        }
    }
    return hdrMap;
