private static BomCharset detectCharsetFromBom(ByteBuffer byteData) {
    if (byteData.remaining() < 2) {
        return null;
    }

    byteData.mark();
    try {
        byte first = byteData.get();
        byte second = byteData.get();

        // Check for UTF-16 BE BOM: FE FF
        if (first == (byte) 0xFE && second == (byte) 0xFF) {
            return new BomCharset("UTF-16BE", 2);
        }
        // Check for UTF-16 LE BOM: FF FE  
        if (first == (byte) 0xFF && second == (byte) 0xFE) {
            // Check if it's actually UTF-32 LE by looking ahead
            if (byteData.remaining() >= 2) {
                byte third = byteData.get();
                byte fourth = byteData.get();
                if (third == 0x00 && fourth == 0x00) {
                    return new BomCharset("UTF-32LE", 4);
                }
                byteData.position(byteData.position() - 2); // reset position
            }
            return new BomCharset("UTF-16LE", 2);
        }

        // Check for UTF-8 BOM: EF BB BF
        if (first == (byte) 0xEF && second == (byte) 0xBB) {
            if (byteData.remaining() >= 1 && byteData.get() == (byte) 0xBF) {
                return new BomCharset("UTF-8", 3);
            }
            byteData.position(byteData.position() - 1); // reset position
        }

        // Check for UTF-32 BE BOM: 00 00 FE FF
        if (first == 0x00 && second == 0x00) {
            if (byteData.remaining() >= 2) {
                byte third = byteData.get();
                byte fourth = byteData.get();
                if (third == (byte) 0xFE && fourth == (byte) 0xFF) {
                    return new BomCharset("UTF-32BE", 4);
                }
            }
        }

        return null;
    } finally {
        byteData.reset();
    }
}

