protected double getInitialDomain(double p) {
    double ret;
    double d = getDenominatorDegreesOfFreedom();
    if (d <= 2.0) {
        // Use a reasonable default when denominator degrees of freedom <= 2
        // The mode of F distribution is used as initial domain when d1 > 2
        // For d1 <= 2, we use a safe positive value
        ret = 1.0;
    } else {
        // use mean
        ret = d / (d - 2.0);
    }
    return ret;
}

protected double getInitialDomain(double p) {
    double ret;
    double d = getDenominatorDegreesOfFreedom();
    // use mean
    if (d <= 2.0) {
        // For denominator degrees of freedom <= 2, the mean is undefined
        // Use median approximation or a safe default value
        ret = 1.0;
    } else {
        ret = d / (d - 2.0);
    }
    return ret;
}

