                "observed, expected array lengths incorrect");
    }
    if (!isPositive(expected) || !isNonNegative(observed)) {
        throw new IllegalArgumentException(
            "observed counts must be non-negative and expected counts must be postive");
    }

    // Calculate sum of observed values
    double sumObserved = 0.0d;
    for (int i = 0; i < observed.length; i++) {
        sumObserved += observed[i];
    }

    // Calculate sum of expected values
    double sumExpected = 0.0d;
    for (int i = 0; i < expected.length; i++) {
        sumExpected += expected[i];
    }

    // Rescale expected values if sums are not equal
    double ratio = 1.0d;
    if (Math.abs(sumObserved - sumExpected) > 10 * Math.ulp(Math.max(sumObserved, sumExpected))) {
        ratio = sumObserved / sumExpected;
    }

    double sumSq = 0.0d;
    double dev = 0.0d;
    for (int i = 0; i < observed.length; i++) {
        double scaledExpected = expected[i] * ratio;
        dev = ((double) observed[i] - scaledExpected);
        sumSq += dev * dev / scaledExpected;
    }
    return sumSq;
}

